const now = new Date();
const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000).toISOString();
const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString();
return [{ json: { fourteenDaysAgo, thirtyDaysAgo, now: now.toISOString() } }];

const leadsRes = $('HTTP — Leads contactados').first().json;
const partnersRes = $('HTTP — Parceiros contactados').first().json;

const fourteenDaysAgo = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000);
const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

// Leads sem resposta há 14+ dias
const dormantLeads = (leadsRes.data || []).filter(l => {
  if (!l.last_contact_at) return false;
  return new Date(l.last_contact_at) < fourteenDaysAgo;
});

// Parceiros sem contacto há 30+ dias
const dormantPartners = (partnersRes.data || []).filter(p => {
  if (!p.last_contact_at) return true; // never contacted
  return new Date(p.last_contact_at) < thirtyDaysAgo;
});

if (dormantLeads.length === 0 && dormantPartners.length === 0) return [];

const all = [
  ...dormantLeads.map(l => ({ ...l, _type: 'lead', _days: Math.floor((Date.now() - new Date(l.last_contact_at).getTime()) / 86400000) })),
  ...dormantPartners.map(p => ({ ...p, _type: 'partner', _days: p.last_contact_at ? Math.floor((Date.now() - new Date(p.last_contact_at).getTime()) / 86400000) : 999 })),
];

return all.map(item => ({ json: item }));

