// Generate daily digest summary
const items = $input.all();
const leads = items.filter(i => i.json._type === 'lead');
const partners = items.filter(i => i.json._type === 'partner');

if (leads.length + partners.length === 0) return [];

return [{ json: {
  total_leads: leads.length,
  total_partners: partners.length,
  summary: `Leads dormentes: ${leads.length} | Parceiros dormentes: ${partners.length}`
}}];
